/**
 * Generate permission test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generatePermissionTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generatePermissionTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generatePermissionTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<PermissionCreateRequest> = {}
): PermissionCreateRequest {
  let baseData: PermissionCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalPermissionFixture };
      break;

    case 'complete':
      baseData = { ...completePermissionFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidPermissionFixture } as PermissionCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniquePermissionFixture,
        code: `TST-${generateUniqueId()}`.substring(0, 20),
      };
      break;

    default:
      baseData = { ...completePermissionFixture };
  }

  return { ...baseData, ...overrides };
}

/**
 * Generate multiple permission fixtures
 *
 * @param count - Number of fixtures to generate
 * @param pattern - The test data pattern to use as base
 * @param modifier - Optional function to modify each fixture
 * @returns Array of generated test data
 *
 * @example
 * ```typescript
 * // Generate 5 unique fixtures
 * const fixtures = generateMultiplePermissionFixtures(5, 'unique');
 *
 * // Generate fixtures with sequential numbering
 * const numbered = generateMultiplePermissionFixtures(3, 'complete', (data, index) => ({
 *   ...data,
 *   name: `Permission #${index + 1}`,
 * }));
 * ```
 */
export function generateMultiplePermissionFixtures(
  count: number,
  pattern: TestDataPattern = 'unique',
  modifier?: (data: PermissionCreateRequest, index: number) => PermissionCreateRequest
): PermissionCreateRequest[] {
  const fixtures: PermissionCreateRequest[] = [];

  for (let i = 0; i < count; i++) {
    let fixture = generatePermissionTestData(pattern);

    if (modifier) {
      fixture = modifier(fixture, i);
    } else if (pattern === 'unique') {
      // Add index to ensure uniqueness even with same timestamp
      fixture.code = `TST-${i}-${generateUniqueId()}`.substring(0, 20);
    }

    fixtures.push(fixture);
  }

  return fixtures;
}

